import type { PaymentStore } from "./payment-store";
import type { OrderStatus, PaymentEvent } from "./types";

const statusByType: Record<PaymentEvent["type"], OrderStatus> = {
  payment_pending: "pending",
  payment_succeeded: "paid",
  payment_failed: "failed",
};

export function handlePaymentEvent(store: PaymentStore, event: PaymentEvent): void {
  store.upsertOrder({
    orderId: event.orderId,
    status: statusByType[event.type],
    amountCents: event.amountCents,
  });
  if (event.type === "payment_succeeded") {
    store.recordCharge(event.orderId, event.amountCents);
  }
}

import type { Order } from "./types";

export class PaymentStore {
  private readonly orders = new Map<string, Order>();
  private readonly processedEventIds = new Set<string>();
  private readonly ledger: string[] = [];

  hasProcessedEvent(eventId: string): boolean {
    return this.processedEventIds.has(eventId);
  }

  markEventProcessed(eventId: string): void {
    this.processedEventIds.add(eventId);
  }

  getOrder(orderId: string): Order | undefined {
    return this.orders.get(orderId);
  }

  upsertOrder(order: Order): void {
    this.orders.set(order.orderId, order);
  }

  recordCharge(orderId: string, amountCents: number): void {
    this.ledger.push(`charge:${orderId}:${amountCents}`);
  }

  ledgerEntries(): readonly string[] {
    return [...this.ledger];
  }

  allOrders(): readonly Order[] {
    return [...this.orders.values()];
  }
}

export type OrderStatus = "pending" | "paid" | "failed";

export type PaymentEventType =
  | "payment_pending"
  | "payment_succeeded"
  | "payment_failed";

export interface PaymentEvent {
  eventId: string;
  orderId: string;
  type: PaymentEventType;
  amountCents: number;
}

export interface Order {
  orderId: string;
  status: OrderStatus;
  amountCents: number;
}

import { describe, expect, it } from "vitest";

import { PaymentStore } from "../src/payment-store";
import { handlePaymentEvent } from "../src/webhook-handler";

describe("payment idempotency acceptance", () => {
  it("processes a duplicate event exactly once", () => {
    const store = new PaymentStore();
    const event = {
      eventId: "evt_duplicate",
      orderId: "order_1",
      type: "payment_succeeded",
      amountCents: 1000,
    } as const;

    handlePaymentEvent(store, event);
    handlePaymentEvent(store, event);

    const charges = store.ledgerEntries().filter((entry) => entry.startsWith("charge:order_1"));
    expect(charges).toHaveLength(1);
  });

  it("protects a paid order from a late pending event", () => {
    const store = new PaymentStore();
    handlePaymentEvent(store, {
      eventId: "evt_paid",
      orderId: "order_1",
      type: "payment_succeeded",
      amountCents: 1000,
    });
    handlePaymentEvent(store, {
      eventId: "evt_late_pending",
      orderId: "order_1",
      type: "payment_pending",
      amountCents: 1000,
    });

    expect(store.getOrder("order_1")?.status).toBe("paid");
  });

  it("protects a paid order from a later failed event", () => {
    const store = new PaymentStore();
    handlePaymentEvent(store, {
      eventId: "evt_paid",
      orderId: "order_1",
      type: "payment_succeeded",
      amountCents: 1000,
    });
    handlePaymentEvent(store, {
      eventId: "evt_later_failed",
      orderId: "order_1",
      type: "payment_failed",
      amountCents: 1000,
    });

    expect(store.getOrder("order_1")?.status).toBe("paid");
  });
});

